## 7. gRPC Proto 설계

파일 위치: `protobuf/src/main/proto/`

### user/user_service.proto

```protobuf
syntax = "proto3";
package user;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.user";

service UserService {
  rpc GetUser(GetUserRequest) returns (GetUserResponse);
  rpc GetUsers(GetUsersRequest) returns (GetUsersResponse);
  rpc UpdateProfile(UpdateProfileRequest) returns (UpdateProfileResponse);
  rpc GetMannerScore(GetMannerScoreRequest) returns (GetMannerScoreResponse);
  rpc UpdateMannerScore(UpdateMannerScoreRequest) returns (UpdateMannerScoreResponse);
}

message User {
  string id = 1;
  string nickname = 2;
  int32 gender = 3;
  string birth_date = 4;
  int32 manner_score = 5;
  int32 status = 6;
  optional string country_code = 7;
  string created_at = 8;
}

message Profile {
  string id = 1;
  string user_id = 2;
  optional string bio = 3;
  optional string profile_image_url = 4;
  repeated string voice_sample_urls = 5;
  int32 height = 6;
  optional string job = 7;
  optional string region = 8;
  repeated string interests = 9;
  bool is_profile_public = 10;
}

message GetUserRequest {
  string user_id = 1;
}
message GetUserResponse {
  User user = 1;
  optional Profile profile = 2;
}

message GetMannerScoreRequest { string user_id = 1; }
message GetMannerScoreResponse { int32 manner_score = 1; }

message UpdateMannerScoreRequest {
  string user_id = 1;
  int32 delta = 2;   // 양수=증가, 음수=감소
}
message UpdateMannerScoreResponse { int32 new_score = 1; }
```

### match/match_service.proto

```protobuf
syntax = "proto3";
package match;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.match";

service MatchService {
  rpc CreateMatch(CreateMatchRequest) returns (CreateMatchResponse);
  rpc RespondMatch(RespondMatchRequest) returns (RespondMatchResponse);
  rpc GetMatch(GetMatchRequest) returns (GetMatchResponse);
  rpc ListMatches(ListMatchesRequest) returns (ListMatchesResponse);
}

message Match {
  string id = 1;
  string requester_id = 2;
  string receiver_id = 3;
  string status = 4;       // PENDING/ACCEPTED/REJECTED/EXPIRED
  optional string responded_at = 5;
  optional string expired_at = 6;
  string created_at = 7;
}

message CreateMatchRequest {
  string requester_id = 1;
  string receiver_id = 2;
}
message CreateMatchResponse { Match match = 1; }

message RespondMatchRequest {
  string match_id = 1;
  string user_id = 2;
  bool accept = 3;
}
message RespondMatchResponse { Match match = 1; }

message ListMatchesRequest {
  string user_id = 1;
  optional string status = 2;
  int32 limit = 3;
  int32 offset = 4;
}
message ListMatchesResponse { repeated Match matches = 1; }
```

### call/call_service.proto

```protobuf
syntax = "proto3";
package call;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.call";

service CallService {
  rpc InitiateCall(InitiateCallRequest) returns (InitiateCallResponse);
  rpc RespondCall(RespondCallRequest) returns (RespondCallResponse);
  rpc EndCall(EndCallRequest) returns (EndCallResponse);
  rpc GetCall(GetCallRequest) returns (GetCallResponse);
  rpc ListCallHistory(ListCallHistoryRequest) returns (ListCallHistoryResponse);
}

message Call {
  string id = 1;
  string caller_id = 2;
  string callee_id = 3;
  string status = 4;
  string call_type = 5;
  int32 duration_seconds = 6;
  optional string started_at = 7;
  optional string ended_at = 8;
  string created_at = 9;
}

message CallSession {
  string call_id = 1;
  string rtc_room_id = 2;
  string token = 3;
}

message InitiateCallRequest {
  string caller_id = 1;
  string callee_id = 2;
  string call_type = 3;
}
message InitiateCallResponse { CallSession session = 1; }

message RespondCallRequest {
  string call_id = 1;
  string user_id = 2;
  bool accept = 3;
}
message RespondCallResponse { optional CallSession session = 1; }

message EndCallRequest {
  string call_id = 1;
  string ended_by = 2;
}
message EndCallResponse { Call call = 1; }
```

### chat/chat_service.proto

```protobuf
syntax = "proto3";
package chat;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.chat";

service ChatService {
  rpc SendMessage(SendMessageRequest) returns (SendMessageResponse);
  rpc ListMessages(ListMessagesRequest) returns (ListMessagesResponse);
  rpc MarkAsRead(MarkAsReadRequest) returns (MarkAsReadResponse);
  rpc ListChatRooms(ListChatRoomsRequest) returns (ListChatRoomsResponse);
}

message Message {
  string message_id = 1;
  string room_id = 2;
  string sender_id = 3;
  string message_type = 4;       // TEXT/AUDIO/IMAGE
  optional string content = 5;
  optional string audio_url = 6;
  bool is_deleted = 7;
  optional string read_at = 8;
  string created_at = 9;
}

message SendMessageRequest {
  string room_id = 1;
  string sender_id = 2;
  string message_type = 3;
  optional string content = 4;
  optional string audio_url = 5;
}
message SendMessageResponse { Message message = 1; }

message ListMessagesRequest {
  string room_id = 1;
  int32 limit = 2;
  optional string last_message_id = 3;    // 커서 기반 페이징
}
message ListMessagesResponse { repeated Message messages = 1; }

message MarkAsReadRequest {
  string room_id = 1;
  string user_id = 2;
  string message_id = 3;
